                        if isinstance(values[0], (int, float)):
                            group_stats[metadata_key + '_avg'] = sum(values) / len(values)
                            group_stats[metadata_key + '_max'] = max(values)
                            group_stats[metadata_key + '_min'] = min(values)
                        else:
                            # For non-numeric values, use first value as representative
